import { useEffect, useState } from "react";
import { useParams, Link } from "react-router-dom";
import { 
  tmdbAPI, 
  Credits,
  getImageUrl
} from "@/services/tmdb";
import { useToast } from "@/components/ui/use-toast";
import { Button } from "@/components/ui/button";
import { ArrowLeft } from "lucide-react";
import NotFound from "./NotFound";

const MovieCast = () => {
  const { id } = useParams<{ id: string }>();
  const { toast } = useToast();
  const [credits, setCredits] = useState<Credits | null>(null);
  const [movieTitle, setMovieTitle] = useState<string>("");
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [notFound, setNotFound] = useState(false);

  useEffect(() => {
    const fetchMovieCast = async () => {
      if (!id) return;

      try {
        setLoading(true);
        setError(null);
        setNotFound(false);

        const movieId = parseInt(id);

        const [creditsData, movieData] = await Promise.all([
          tmdbAPI.getMovieCredits(movieId),
          tmdbAPI.getMovieDetails(movieId),
        ]);

        setCredits(creditsData);
        setMovieTitle(movieData.title);
      } catch (err) {
        console.error("Error fetching movie cast:", err);

        if ((err as any)?.message?.includes("404")) {
          setNotFound(true);
        } else {
          setError("Failed to load cast data. Please try again.");
          toast({
            variant: "destructive", 
            title: "Error",
            description: "Failed to load cast details. Please try again later.",
          });
        }
      } finally {
        setLoading(false);
      }
    };

    fetchMovieCast();
  }, [id, toast]);

  if (notFound) {
    return <NotFound />;
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="animate-pulse text-2xl text-muted-foreground">Loading...</div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen gap-4">
        <p className="text-xl text-destructive">{error}</p>
        <Button asChild>
          <Link to={`/movies/${id}`}>Back to Movie</Link>
        </Button>
      </div>
    );
  }

  // Cast and crew from credits
  const cast = credits?.cast || [];
  const crew = credits?.crew || [];

  // Get all unique departments
  const departments = [...new Set(crew.map(person => person.department))].sort();

  return (
    <div className="min-h-screen pb-10 pt-24">
      <div className="container">
        <div className="mb-8">
          <Button variant="ghost" asChild className="mb-4 -ml-3 gap-1">
            <Link to={`/movies/${id}`}>
              <ArrowLeft size={16} />
              Back to Movie
            </Link>
          </Button>
          <h1 className="text-3xl font-bold">
            Cast & Crew
            <span className="text-muted-foreground ml-2">
              {movieTitle}
            </span>
          </h1>
        </div>

        {/* Cast Section */}
        <div className="mb-12">
          <h2 className="text-2xl font-semibold mb-6">Cast</h2>
          {cast.length > 0 ? (
            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4 md:gap-6">
              {cast.map(person => (
                <Link 
                  key={person.id} 
                  to={`/people/${person.id}`}
                  className="block group"
                >
                  <div className="aspect-[2/3] rounded-lg overflow-hidden bg-card">
                    <img
                      src={getImageUrl(person.profile_path, "w185")}
                      alt={person.name}
                      className="w-full h-full object-cover group-hover:scale-105 transition-transform"
                      loading="lazy"
                    />
                  </div>
                  <div className="mt-2">
                    <h4 className="font-medium text-sm">{person.name}</h4>
                    <p className="text-xs text-muted-foreground">{person.character}</p>
                  </div>
                </Link>
              ))}
            </div>
          ) : (
            <p className="text-muted-foreground">No cast information available.</p>
          )}
        </div>

        {/* Crew Section - Organized by Department */}
        <div>
          <h2 className="text-2xl font-semibold mb-6">Crew</h2>
          {departments.length > 0 ? (
            <div className="space-y-8">
              {departments.map(department => {
                const departmentCrew = crew.filter(person => person.department === department);
                return (
                  <div key={department} className="space-y-4">
                    <h3 className="text-xl font-medium">{department}</h3>
                    <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4 md:gap-6">
                      {departmentCrew.map(person => (
                        <Link 
                          key={`${person.id}-${person.job}`} 
                          to={`/people/${person.id}`}
                          className="block group"
                        >
                          <div className="aspect-[2/3] rounded-lg overflow-hidden bg-card">
                            <img
                              src={getImageUrl(person.profile_path, "w185")}
                              alt={person.name}
                              className="w-full h-full object-cover group-hover:scale-105 transition-transform"
                              loading="lazy"
                            />
                          </div>
                          <div className="mt-2">
                            <h4 className="font-medium text-sm">{person.name}</h4>
                            <p className="text-xs text-muted-foreground">{person.job}</p>
                          </div>
                        </Link>
                      ))}
                    </div>
                  </div>
                );
              })}
            </div>
          ) : (
            <p className="text-muted-foreground">No crew information available.</p>
          )}
        </div>
      </div>
    </div>
  );
};

export default MovieCast;

import { useEffect, useState } from "react";
import { useParams, Link, useNavigate } from "react-router-dom";
import { 
  tmdbAPI, 
  MovieDetails as MovieDetailsType, 
  Credits,
  Video,
  Movie,
  getImageUrl,
  BACKDROP_SIZES,
  POSTER_SIZES
} from "@/services/tmdb";
import { useToast } from "@/components/ui/use-toast";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Separator } from "@/components/ui/separator";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import MediaRow from "@/components/MediaRow";
import TrailerModal from "@/components/TrailerModal";
import WatchProviders from "@/components/WatchProviders";
import { Play, Star, Calendar, Clock, Users, DollarSign } from "lucide-react";
import NotFound from "./NotFound";
import { extractId, moviePath } from "@/lib/slug";

const MovieDetails = () => {
  const { slug } = useParams<{ slug: string }>();
  const navigate = useNavigate();
  const { toast } = useToast();
  const [movie, setMovie] = useState<MovieDetailsType | null>(null);
  const [credits, setCredits] = useState<Credits | null>(null);
  const [videos, setVideos] = useState<Video[]>([]);
  const [similarMovies, setSimilarMovies] = useState<Movie[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [notFound, setNotFound] = useState(false);
  const [trailerOpen, setTrailerOpen] = useState(false);

  useEffect(() => {
    const fetchMovieDetails = async () => {
      if (!slug) return;
      try {
        setLoading(true);
        setError(null);
        setNotFound(false);

        const movieId = extractId(slug);

        const [movieData, creditsData, videosData, similarData] = await Promise.all([
          tmdbAPI.getMovieDetails(movieId),
          tmdbAPI.getMovieCredits(movieId),
          tmdbAPI.getMovieVideos(movieId),
          tmdbAPI.getSimilarMovies(movieId),
        ]);

        setMovie(movieData);
        setCredits(creditsData);
        setVideos(videosData.results);
        setSimilarMovies(similarData.results);

        // Redirect to slug URL if not already there
        const expectedSlug = moviePath(movieData.id, movieData.title).replace("/movies/", "");
        if (slug !== expectedSlug) {
          navigate(moviePath(movieData.id, movieData.title), { replace: true });
        }
      } catch (err) {
        console.error("Error fetching movie details:", err);
        if ((err as any)?.message?.includes("404")) {
          setNotFound(true);
        } else {
          setError("Ocorreu um erro ao carregar os dados do filme. Por favor, tente novamente.");
          toast({
            variant: "destructive",
            title: "Erro",
            description: "N├úo foi poss├¡vel carregar os detalhes do filme. Tente novamente mais tarde.",
          });
        }
      } finally {
        setLoading(false);
      }
    };

    fetchMovieDetails();
  }, [slug, toast, navigate]);

  const formatRuntime = (minutes: number | null) => {
    if (!minutes) return "N/A";
    const hours = Math.floor(minutes / 60);
    const mins = minutes % 60;
    return `${hours}h ${mins}min`;
  };

  const formatDate = (dateStr: string) => {
    if (!dateStr) return "N/A";
    return new Intl.DateTimeFormat("pt-BR", {
      year: "numeric", month: "short", day: "numeric",
    }).format(new Date(dateStr));
  };

  const formatCurrency = (value: number) =>
    new Intl.NumberFormat("pt-BR", { style: "currency", currency: "USD", notation: "compact", maximumFractionDigits: 1 }).format(value);

  const getTrailer = () => {
    return (
      videos.find(v => v.type === "Trailer" && v.site === "YouTube" && v.official) ||
      videos.find(v => v.site === "YouTube")
    );
  };

  if (notFound) return <NotFound />;

  if (loading && !movie) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="animate-pulse text-2xl text-muted-foreground">Carregando...</div>
      </div>
    );
  }

  if (error && !movie) {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen gap-4">
        <p className="text-xl text-destructive">{error}</p>
        <Button asChild><Link to="/">Voltar ao In├¡cio</Link></Button>
      </div>
    );
  }

  if (!movie) return null;

  const trailer = getTrailer();
  const cast = credits?.cast?.slice(0, 10) || [];
  const directors = credits?.crew?.filter(p => p.job === "Director") || [];
  const movieId = extractId(slug!);

  return (
    <div className="min-h-screen pb-10 pt-16">
      {/* Trailer Modal */}
      {trailerOpen && trailer && (
        <TrailerModal
          videoKey={trailer.key}
          title={`${movie.title} ÔÇô Trailer`}
          onClose={() => setTrailerOpen(false)}
        />
      )}

      {/* Backdrop */}
      <div className="relative w-full h-[50vh] md:h-[70vh] overflow-hidden">
        <div
          className="absolute inset-0 bg-cover bg-center scale-105"
          style={{ backgroundImage: `url(${getImageUrl(movie.backdrop_path, BACKDROP_SIZES.ORIGINAL)})` }}
        />
        <div className="absolute inset-0 bg-gradient-to-r from-black/95 via-black/70 to-black/20" />
        <div className="absolute inset-0 bg-gradient-to-t from-black/90 to-transparent" />

        <div className="relative container z-10 h-full flex items-end pb-10 md:pb-14">
          <div className="flex flex-col md:flex-row gap-6 md:gap-10 w-full">
            {/* Poster */}
            <div className="hidden md:block flex-shrink-0 w-48 lg:w-60">
              <img
                src={getImageUrl(movie.poster_path, POSTER_SIZES.MEDIUM)}
                alt={movie.title}
                className="w-full rounded-xl overflow-hidden shadow-2xl border border-white/10"
              />
            </div>

            {/* Info */}
            <div className="flex-1">
              <h1 className="text-3xl md:text-4xl lg:text-5xl font-extrabold tracking-tight">
                {movie.title}
                {movie.release_date && (
                  <span className="text-muted-foreground font-normal ml-3 text-2xl">
                    ({new Date(movie.release_date).getFullYear()})
                  </span>
                )}
              </h1>

              {movie.tagline && (
                <p className="text-base italic text-muted-foreground mt-2">"{movie.tagline}"</p>
              )}

              {/* Meta row */}
              <div className="flex flex-wrap items-center gap-x-5 gap-y-2 mt-4 text-sm">
                {movie.vote_average > 0 && (
                  <div className="flex items-center gap-1.5">
                    <Star size={16} className="fill-yellow-400 text-yellow-400" />
                    <span className="font-semibold">{movie.vote_average.toFixed(1)}</span>
                    <span className="text-muted-foreground">/ 10</span>
                  </div>
                )}
                {movie.release_date && (
                  <div className="flex items-center gap-1.5 text-muted-foreground">
                    <Calendar size={14} />
                    <span>{formatDate(movie.release_date)}</span>
                  </div>
                )}
                {movie.runtime && (
                  <div className="flex items-center gap-1.5 text-muted-foreground">
                    <Clock size={14} />
                    <span>{formatRuntime(movie.runtime)}</span>
                  </div>
                )}
              </div>

              {/* Genres */}
              <div className="flex flex-wrap gap-2 mt-4">
                {movie.genres?.map(genre => (
                  <Link key={genre.id} to={`/movies?genre=${genre.id}`}>
                    <Badge variant="secondary" className="rounded-full hover:bg-primary hover:text-white transition-colors">
                      {genre.name}
                    </Badge>
                  </Link>
                ))}
              </div>

              {/* Trailer button */}
              {trailer && (
                <div className="mt-6">
                  <Button
                    onClick={() => setTrailerOpen(true)}
