          </div>
        </div>
      </div>

      {/* Main content */}
      <div className="container mt-8 md:mt-10">
        <div className="grid grid-cols-1 md:grid-cols-[1fr_300px] gap-6 lg:gap-10">
          {/* Main column */}
          <div>
            <Tabs defaultValue="overview">
