        </div>

        {/* Filmes Similares */}
        {similarMovies.length > 0 && (
          <div className="mt-10">
            <MediaRow title="Filmes Similares" items={similarMovies} type="movie" />
          </div>
        )}
      </div>
    </div>
  );
};

