import { useParams, useNavigate, useSearchParams } from "react-router-dom";
import { Clock, ChevronLeft, CalendarDays, Share2 } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { useEffect, useState } from "react";
import { supabase } from "@/lib/supabase";

const NewsArticlePage = () => {
  const { id } = useParams();
  const [searchParams] = useSearchParams();
  const isPreview = searchParams.get("preview") === "true";
  const navigate = useNavigate();
  const [article, setArticle] = useState<any>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchArticle = async () => {
      setLoading(true);
      let query = supabase.from("articles").select("*").eq("slug", id);
      
      // Se n├úo for preview, garantir que esteja published
      if (!isPreview) {
        query = query.eq("status", "published");
      }
      
      const { data, error } = await query.single();
      
      if (data && !error) {
        setArticle(data);
        // Atualiza t├¡tulo da aba
        document.title = `${data.title} | Deazons`;
        // Adiciona Meta Description real na head
        if (data.meta_description) {
          let meta = document.querySelector('meta[name="description"]');
          if (!meta) {
            meta = document.createElement('meta');
            meta.setAttribute('name', 'description');
            document.head.appendChild(meta);
          }
          meta.setAttribute('content', data.meta_description);
        }
      }
      setLoading(false);
    };

    if (id) {
      fetchArticle();
    }
  }, [id, isPreview]);

  if (loading) {
    return (
      <div className="min-h-screen pt-32 pb-20 flex flex-col items-center justify-center -mt-20">
        <div className="animate-pulse flex flex-col items-center">
          <div className="w-16 h-16 border-4 border-primary border-t-transparent rounded-full animate-spin mb-4" />
          <p className="text-muted-foreground">Carregando artigo...</p>
        </div>
      </div>
    );
  }

  if (!article) {
    return (
      <div className="min-h-screen pt-32 pb-20 flex flex-col items-center justify-center -mt-20">
        <h2 className="text-2xl font-bold mb-4">Artigo n├úo encontrado</h2>
        <Button onClick={() => navigate("/noticias")} variant="default">
          Voltar para Not├¡cias
        </Button>
      </div>
    );
  }

  return (
    <article className="min-h-screen pt-24 pb-20 bg-background text-foreground">
      <div className="max-w-3xl mx-auto px-4 sm:px-6">
        {/* Navega├º├úo */}
        <Button
          variant="ghost"
          size="sm"
          className="mb-8 pl-0 hover:bg-transparent hover:text-primary transition-colors gap-2 text-muted-foreground"
          onClick={() => navigate("/noticias")}
        >
          <ChevronLeft className="w-4 h-4" />
          Voltar para Noticias
        </Button>

        {/* Cabe├ºalho do Artigo */}
        <header className="mb-8 sm:mb-12">
          <Badge className="mb-4 bg-primary/20 text-primary hover:bg-primary/30 px-3 py-1 rounded-full text-sm font-semibold border-none">
            {article.category}
          </Badge>
          
          <h1 className="text-3xl sm:text-4xl md:text-5xl font-extrabold tracking-tight mb-6 leading-tight">
            {article.title}
          </h1>

          <div className="flex flex-wrap items-center gap-4 text-sm text-muted-foreground border-b border-border/50 pb-6 mb-8">
            <div className="flex items-center gap-2">
              <CalendarDays className="w-4 h-4" />
              <time>
                {new Date(article.published_at || article.created_at).toLocaleDateString("pt-BR", {
                  day: "2-digit",
                  month: "long",
                  year: "numeric"
                })}
              </time>
            </div>
            <div className="flex items-center gap-2">
              <Clock className="w-4 h-4" />
              <span>{Math.max(3, Math.ceil(article.content?.split(' ').length / 200))} min de leitura</span>
            </div>
            
            <div className="flex-1" />
            
            <Button variant="outline" size="sm" className="gap-2 h-8 rounded-full">
              <Share2 className="w-3 h-3" />
              Compartilhar
            </Button>
          </div>
        </header>

        {/* Imagem Principal */}
        <figure className="mb-10 sm:mb-14 overflow-hidden rounded-2xl border border-border/30 bg-muted/20">
          <img
            src={article.image_url || "https://images.unsplash.com/photo-1489599849927-2ee91cede3ba?q=80&w=2670&auto=format&fit=crop"}
            alt={article.image_alt || "Capa da Not├¡cia"}
            className="w-full aspect-[16/9] md:aspect-[21/9] object-cover"
          />
        </figure>

        {/* Conte├║do Renderizado a partir do Gemini */}
        <div 
          className="prose prose-invert prose-lg max-w-none prose-headings:font-bold prose-headings:text-foreground prose-p:text-muted-foreground prose-p:leading-relaxed prose-a:text-primary hover:prose-a:text-primary/80"
          dangerouslySetInnerHTML={{ __html: article.content }}
        />
        
        {/* AdSense Ads Area */}
        <div className="mt-16 pt-8 border-t border-border/50">
          {/* O script do AdSense seria injetado aqui */}
          <div className="w-full h-32 bg-secondary/30 rounded-lg flex items-center justify-center border border-border/20 text-muted-foreground/50 text-sm">
            An├║ncio (AdSense Space)
          </div>
        </div>
      </div>
    </article>
  );
};

