import { useParams } from "react-router-dom";
import { useState, useEffect } from "react";
import { 
  tmdbAPI, 
  PersonDetails as PersonDetailsType,
  Movie,
  TVShow
} from "@/services/tmdb";
import { useToast } from "@/components/ui/use-toast";
import MediaGrid from "@/components/MediaGrid";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Button } from "@/components/ui/button";
import { Link } from "react-router-dom";
import { Film, Tv, ArrowLeft } from "lucide-react";
import NotFound from "./NotFound";

const PersonFilmography = () => {
  const { id, mediaType } = useParams<{ id: string; mediaType: string }>();
  const { toast } = useToast();
  const [person, setPerson] = useState<PersonDetailsType | null>(null);
  const [movieCredits, setMovieCredits] = useState<{ cast: Movie[]; crew: Movie[] } | null>(null);
  const [tvCredits, setTVCredits] = useState<{ cast: TVShow[]; crew: TVShow[] } | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [notFound, setNotFound] = useState(false);

  const activeTab = mediaType === "tv" ? "tv" : "movies";

  useEffect(() => {
    const fetchPersonData = async () => {
      if (!id) return;

      try {
        setLoading(true);
        setError(null);
        setNotFound(false);

        const personId = parseInt(id);

        const [personData, personMovieCredits, personTVCredits] = await Promise.all([
          tmdbAPI.getPersonDetails(personId),
          tmdbAPI.getPersonMovieCredits(personId),
          tmdbAPI.getPersonTVCredits(personId),
        ]);

        setPerson(personData);
        setMovieCredits(personMovieCredits);
        setTVCredits(personTVCredits);
      } catch (err) {
        console.error("Error fetching person filmography:", err);

        if ((err as any)?.message?.includes("404")) {
          setNotFound(true);
        } else {
          setError("Ocorreu um erro ao carregar os dados da pessoa. Por favor, tente novamente.");
          toast({
            variant: "destructive", 
            title: "Erro",
            description: "N├úo foi poss├¡vel carregar os dados da filmografia. Tente novamente mais tarde.",
          });
        }
      } finally {
        setLoading(false);
      }
    };

    fetchPersonData();
  }, [id, toast]);

  // Helpers for sorting credits by popularity
  const sortMoviesByPopularity = (movies: Movie[]) => {
    return [...movies].sort((a, b) => b.popularity - a.popularity);
  };

  const sortTVShowsByPopularity = (shows: TVShow[]) => {
    return [...shows].sort((a, b) => b.popularity - a.popularity);
  };

  if (notFound) {
    return <NotFound />;
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="animate-pulse text-2xl text-muted-foreground">Carregando...</div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen gap-4">
        <p className="text-xl text-destructive">{error}</p>
        <Button asChild>
          <Link to="/">Voltar para Home</Link>
        </Button>
      </div>
    );
  }

  // Sort credits by popularity
  const sortedMovieCast = movieCredits?.cast ? sortMoviesByPopularity(movieCredits.cast) : [];
  const sortedTVCast = tvCredits?.cast ? sortTVShowsByPopularity(tvCredits.cast) : [];

  return (
    <div className="min-h-screen pb-10 pt-24">
      <div className="container">
        <div className="flex items-center gap-4 mb-8">
          <Button variant="outline" size="icon" asChild>
            <Link to={`/people/${id}`}>
              <ArrowLeft />
            </Link>
          </Button>
          <h1 className="text-2xl md:text-3xl font-bold">
            {person?.name ? `Filmografia de ${person.name}` : 'Filmografia'}
          </h1>
        </div>

        <Tabs defaultValue={activeTab} className="w-full">
          <TabsList className="mb-6">
            <TabsTrigger
              value="movies"
              className="flex items-center gap-2"
              asChild
            >
              <Link to={`/people/${id}/movies`}>
                <Film size={16} />
                Filmes {movieCredits?.cast?.length ? `(${movieCredits.cast.length})` : ''}
              </Link>
            </TabsTrigger>
            <TabsTrigger
              value="tv"
              className="flex items-center gap-2"
              asChild
            >
              <Link to={`/people/${id}/tv`}>
                <Tv size={16} />
                S├®ries {tvCredits?.cast?.length ? `(${tvCredits.cast.length})` : ''}
              </Link>
            </TabsTrigger>
          </TabsList>

          <TabsContent value="movies" className="mt-0">
            <MediaGrid
              items={sortedMovieCast}
              type="movie"
              loading={loading}
              error={error}
              onRetry={() => window.location.reload()}
              onClearFilters={() => {}}
            />
          </TabsContent>

          <TabsContent value="tv" className="mt-0">
            <MediaGrid
              items={sortedTVCast}
              type="tv"
              loading={loading}
              error={error}
              onRetry={() => window.location.reload()}
              onClearFilters={() => {}}
            />
          </TabsContent>
        </Tabs>
      </div>
    </div>
  );
};

export default PersonFilmography;

import { useEffect, useState } from "react";
import { useSearchParams, Link } from "react-router-dom";
import { tmdbAPI, Movie, TVShow, Person } from "@/services/tmdb";
import { useToast } from "@/components/ui/use-toast";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Search as SearchIcon } from "lucide-react";
import MediaCard from "@/components/MediaCard";
import PersonCard from "@/components/PersonCard";

const Search = () => {
  const [searchParams, setSearchParams] = useSearchParams();
  const { toast } = useToast();
  const [query, setQuery] = useState(searchParams.get("q") || "");
  const [movies, setMovies] = useState<Movie[]>([]);
  const [tvShows, setTVShows] = useState<TVShow[]>([]);
  const [people, setPeople] = useState<Person[]>([]);
  const [currentPage, setCurrentPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [activeTab, setActiveTab] = useState("all");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Search when query changes
  useEffect(() => {
    const searchQuery = searchParams.get("q");

    if (searchQuery) {
      setQuery(searchQuery);
      performSearch(searchQuery, 1);
    }
  }, [searchParams]);

  const performSearch = async (searchQuery: string, page: number) => {
    if (!searchQuery.trim()) return;

    try {
      setLoading(true);
      setError(null);

      const searchResults = await tmdbAPI.searchMulti(searchQuery, page);

      // Separate results by type
      const movieResults: Movie[] = [];
      const tvResults: TVShow[] = [];
      const peopleResults: Person[] = [];

      searchResults.results.forEach((item: any) => {
        if (item.media_type === "movie") {
          movieResults.push(item as Movie);
        } else if (item.media_type === "tv") {
          tvResults.push(item as TVShow);
        } else if (item.media_type === "person") {
          peopleResults.push(item as Person);
        }
      });

      setMovies(movieResults);
      setTVShows(tvResults);
      setPeople(peopleResults);
      setCurrentPage(page);
      setTotalPages(searchResults.total_pages > 20 ? 20 : searchResults.total_pages); // Limit to 20 pages
    } catch (err) {
      console.error("Error performing search:", err);
      setError("Ocorreu um erro ao realizar a busca. Por favor, tente novamente.");
      toast({
        variant: "destructive",
        title: "Erro na busca",
        description: "N├úo foi poss├¡vel completar sua busca. Tente novamente mais tarde.",
      });
    } finally {
      setLoading(false);
    }
  };

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    if (query.trim()) {
      setSearchParams({ q: query.trim() });
    }
  };

  const handleTabChange = (value: string) => {
    setActiveTab(value);
  };

  const loadPage = (page: number) => {
    const searchQuery = searchParams.get("q") || "";
    performSearch(searchQuery, page);
  };

  // Calculate total results
  const totalResults = movies.length + tvShows.length + people.length;

  return (
    <div className="min-h-screen pb-10 pt-24">
      <div className="container max-w-6xl">
        <h1 className="text-3xl font-bold mb-6">Busca</h1>

        {/* Search form */}
        <form onSubmit={handleSearch} className="mb-6">
          <div className="flex items-center gap-2">
            <div className="relative flex-1">
              <SearchIcon 
                size={18} 
                className="absolute left-3 top-1/2 transform -translate-y-1/2 text-muted-foreground" 
              />
              <Input
                value={query}
                onChange={(e) => setQuery(e.target.value)}
                className="pl-10"
                placeholder="Filmes, s├®ries, atores..."
              />
            </div>
            <Button type="submit" disabled={loading}>Buscar</Button>
          </div>
        </form>

        {/* Search results */}
        {loading ? (
          <div className="flex items-center justify-center h-60">
            <div className="animate-pulse text-xl text-muted-foreground">Buscando...</div>
          </div>
        ) : error ? (
          <div className="text-center py-10">
            <p className="text-destructive mb-4">{error}</p>
            <Button onClick={() => performSearch(query, 1)}>Tentar novamente</Button>
          </div>
        ) : query && totalResults === 0 ? (
          <div className="text-center py-10">
            <p className="text-xl mb-2">Nenhum resultado encontrado para "{query}"</p>
            <p className="text-muted-foreground">Tente outro termo de busca.</p>
          </div>
        ) : query ? (
          <div className="space-y-8">
            <p className="text-muted-foreground">
              Encontrados {totalResults} resultados para "{query}"
            </p>

            <Tabs
              value={activeTab}
              onValueChange={handleTabChange}
              className="space-y-4"
            >
              <TabsList>
                <TabsTrigger value="all">Todos</TabsTrigger>
                <TabsTrigger value="movies">Filmes ({movies.length})</TabsTrigger>
                <TabsTrigger value="tv">S├®ries ({tvShows.length})</TabsTrigger>
                <TabsTrigger value="people">Pessoas ({people.length})</TabsTrigger>
              </TabsList>

              <TabsContent value="all" className="space-y-8">
                {/* Movies section */}
                {movies.length > 0 && (
                  <div>
                    <div className="flex items-center justify-between mb-4">
                      <h2 className="text-xl font-semibold">Filmes</h2>
                      {movies.length > 6 && (
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => setActiveTab("movies")}
                          className="text-deazon-400 hover:text-deazon-300"
                        >
                          Ver todos
                        </Button>
                      )}
                    </div>

                    <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-4">
                      {movies.slice(0, 6).map((movie) => (
                        <MediaCard key={movie.id} media={movie} type="movie" />
                      ))}
                    </div>
                  </div>
                )}

                {/* TV Shows section */}
                {tvShows.length > 0 && (
                  <div>
                    <div className="flex items-center justify-between mb-4">
                      <h2 className="text-xl font-semibold">S├®ries</h2>
                      {tvShows.length > 6 && (
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => setActiveTab("tv")}
                          className="text-deazon-400 hover:text-deazon-300"
                        >
                          Ver todas
                        </Button>
                      )}
                    </div>

                    <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-4">
                      {tvShows.slice(0, 6).map((show) => (
                        <MediaCard key={show.id} media={show} type="tv" />
                      ))}
                    </div>
                  </div>
                )}

                {/* People section */}
                {people.length > 0 && (
                  <div>
                    <div className="flex items-center justify-between mb-4">
                      <h2 className="text-xl font-semibold">Pessoas</h2>
                      {people.length > 6 && (
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => setActiveTab("people")}
                          className="text-deazon-400 hover:text-deazon-300"
                        >
                          Ver todas
                        </Button>
                      )}
                    </div>

                    <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-4">
                      {people.slice(0, 6).map((person) => (
                        <PersonCard key={person.id} person={person} />
                      ))}
                    </div>
                  </div>
                )}
              </TabsContent>

              <TabsContent value="movies">
                <h2 className="text-xl font-semibold mb-4">Filmes</h2>
                {movies.length > 0 ? (
                  <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
                    {movies.map((movie) => (
                      <MediaCard key={movie.id} media={movie} type="movie" />
                    ))}
                  </div>
                ) : (
                  <p className="text-muted-foreground">Nenhum filme encontrado.</p>
                )}
              </TabsContent>

              <TabsContent value="tv">
                <h2 className="text-xl font-semibold mb-4">S├®ries</h2>
                {tvShows.length > 0 ? (
                  <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
                    {tvShows.map((show) => (
                      <MediaCard key={show.id} media={show} type="tv" />
                    ))}
                  </div>
                ) : (
                  <p className="text-muted-foreground">Nenhuma s├®rie encontrada.</p>
                )}
              </TabsContent>

              <TabsContent value="people">
                <h2 className="text-xl font-semibold mb-4">Pessoas</h2>
                {people.length > 0 ? (
                  <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
                    {people.map((person) => (
                      <PersonCard key={person.id} person={person} />
                    ))}
                  </div>
                ) : (
                  <p className="text-muted-foreground">Nenhuma pessoa encontrada.</p>
                )}
              </TabsContent>
            </Tabs>

            {/* Pagination */}
            {totalPages > 1 && (
              <div className="flex justify-center mt-8">
                <div className="flex gap-2">
                  <Button
                    variant="outline"
                    disabled={currentPage === 1}
                    onClick={() => loadPage(currentPage - 1)}
                  >
                    Anterior
                  </Button>

                  <span className="flex items-center px-4 text-sm">
                    P├ígina {currentPage} de {totalPages}
                  </span>

                  <Button
                    variant="outline"
                    disabled={currentPage === totalPages}
                    onClick={() => loadPage(currentPage + 1)}
                  >
                    Pr├│xima
                  </Button>
                </div>
              </div>
            )}
          </div>
        ) : null}
      </div>
    </div>
  );
};

export default Search;

import { useEffect, useState } from "react";
import { useParams, Link } from "react-router-dom";
import { 
  tmdbAPI, 
  Credits,
  getImageUrl
} from "@/services/tmdb";
import { useToast } from "@/components/ui/use-toast";
import { Button } from "@/components/ui/button";
import { ArrowLeft } from "lucide-react";
import NotFound from "./NotFound";

const TVShowCast = () => {
  const { id } = useParams<{ id: string }>();
  const { toast } = useToast();
  const [credits, setCredits] = useState<Credits | null>(null);
  const [showTitle, setShowTitle] = useState<string>("");
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [notFound, setNotFound] = useState(false);

  useEffect(() => {
    const fetchTVShowCast = async () => {
      if (!id) return;

      try {
        setLoading(true);
        setError(null);
        setNotFound(false);

        const showId = parseInt(id);

        const [creditsData, showData] = await Promise.all([
          tmdbAPI.getTVShowCredits(showId),
          tmdbAPI.getTVShowDetails(showId),
        ]);

        setCredits(creditsData);
        setShowTitle(showData.name);
      } catch (err) {
        console.error("Error fetching TV show cast:", err);

        if ((err as any)?.message?.includes("404")) {
          setNotFound(true);
        } else {
          setError("Failed to load cast data. Please try again.");
          toast({
            variant: "destructive", 
            title: "Error",
            description: "Failed to load cast details. Please try again later.",
          });
        }
      } finally {
        setLoading(false);
      }
    };

    fetchTVShowCast();
  }, [id, toast]);

  if (notFound) {
    return <NotFound />;
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="animate-pulse text-2xl text-muted-foreground">Loading...</div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen gap-4">
        <p className="text-xl text-destructive">{error}</p>
        <Button asChild>
          <Link to={`/tvs/${id}`}>Back to TV Show</Link>
        </Button>
      </div>
    );
  }

  // Cast and crew from credits
  const cast = credits?.cast || [];
  const crew = credits?.crew || [];

  // Get all unique departments
  const departments = [...new Set(crew.map(person => person.department))].sort();

  return (
    <div className="min-h-screen pb-10 pt-24">
      <div className="container">
        <div className="mb-8">
          <Button variant="ghost" asChild className="mb-4 -ml-3 gap-1">
            <Link to={`/tvs/${id}`}>
              <ArrowLeft size={16} />
              Back to TV Show
            </Link>
          </Button>
          <h1 className="text-3xl font-bold">
            Cast & Crew
            <span className="text-muted-foreground ml-2">
              {showTitle}
            </span>
          </h1>
        </div>

        {/* Cast Section */}
        <div className="mb-12">
          <h2 className="text-2xl font-semibold mb-6">Cast</h2>
          {cast.length > 0 ? (
            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4 md:gap-6">
              {cast.map(person => (
                <Link 
                  key={person.id} 
                  to={`/people/${person.id}`}
                  className="block group"
                >
                  <div className="aspect-[2/3] rounded-lg overflow-hidden bg-card">
                    <img
                      src={getImageUrl(person.profile_path, "w185")}
                      alt={person.name}
                      className="w-full h-full object-cover group-hover:scale-105 transition-transform"
                      loading="lazy"
                    />
                  </div>
                  <div className="mt-2">
                    <h4 className="font-medium text-sm">{person.name}</h4>
                    <p className="text-xs text-muted-foreground">{person.character}</p>
                  </div>
                </Link>
              ))}
            </div>
          ) : (
            <p className="text-muted-foreground">No cast information available.</p>
          )}
        </div>

        {/* Crew Section - Organized by Department */}
        <div>
          <h2 className="text-2xl font-semibold mb-6">Crew</h2>
          {departments.length > 0 ? (
            <div className="space-y-8">
              {departments.map(department => {
                const departmentCrew = crew.filter(person => person.department === department);
                return (
                  <div key={department} className="space-y-4">
