import Parser from 'rss-parser';
import { supabaseAdmin, RssSource, Article } from '@/lib/supabase';
import { geminiModel, rewriteArticlePrompt } from '@/lib/gemini';
import { tmdbAPI } from './tmdb';

const CORS_PROXY = 'https://corsproxy.io/?url=';

// Custom fields to parse
const parser = new Parser({
  customFields: {
    item: ['content:encoded', 'description', 'enclosure'],
  },
});

export const getFeedsFromDB = async (): Promise<RssSource[]> => {
  const { data, error } = await supabaseAdmin
    .from('rss_sources')
    .select('*')
    .eq('active', true);

  if (error) {
    console.error('Error fetching RSS sources:', error);
    return [];
  }
  return data || [];
};

const extractTags = (item: any): string[] => {
  if (item.categories && Array.isArray(item.categories)) {
    return item.categories;
  }
  return [];
};

const extractImage = (item: any): string | null => {
  // Try enclosure
  if (item.enclosure && item.enclosure.url) {
    return item.enclosure.url;
  }

  // Try parsing from content
  const content = item['content:encoded'] || item.content || item.description || '';
  const imgMatch = content.match(/<img[^>]+src="([^">]+)"/);
  if (imgMatch && imgMatch[1]) {
    return imgMatch[1];
  }

  return null;
};

// Use TMDB as fallback for images based on movie/tv show title
const getTMDBFallbackImage = async (title: string): Promise<string | null> => {
  try {
    // Basic cleanup of title to improve search
    let searchTitle = title
      .replace(/Review|Cr├¡tica|Trailer|Teaser|Confirmado|Rumor|Entrevista/gi, '')
      .split(':')[0]
      .split('-')[0]
      .trim();

    if (!searchTitle) return null;

    const data = await tmdbAPI.searchMulti(searchTitle);
    const result = data.results.find(
      (r: any) => (r.media_type === 'movie' || r.media_type === 'tv') && 'backdrop_path' in r && r.backdrop_path
    ) as any;

    if (result && result.backdrop_path) {
      return `https://image.tmdb.org/t/p/w1280${result.backdrop_path}`;
    }
    return null;
  } catch (error) {
    console.error('TMDB fallback error for title:', title, error);
    return null;
  }
};

export const fetchAndProcessFeeds = async (
  onProgress: (msg: string) => void
): Promise<void> => {
  onProgress('Buscando fontes cadastradas no banco...');
  const sources = await getFeedsFromDB();

  if (sources.length === 0) {
    onProgress('Nenhuma fonte ativa encontrada.');
    return;
  }

  for (const source of sources) {
    onProgress(`Lendo feed: ${source.name} (${source.url})...`);

    try {
      // Use proxy to avoid CORS errors in browser
      const feedUrl = `${CORS_PROXY}${encodeURIComponent(source.url)}`;
      const feed = await parser.parseURL(feedUrl);

      // update last_fetched
      await supabaseAdmin
        .from('rss_sources')
        .update({ last_fetched: new Date().toISOString() })
        .eq('id', source.id);

      onProgress(`Encontrados ${feed.items.length} itens no feed ${source.name}. Processando novos...`);

      for (const item of feed.items) {
        if (!item.link || !item.title) continue;

        // Check duplicates
        const { data: existing } = await supabaseAdmin
          .from('articles')
          .select('id')
          .eq('source_url', item.link)
          .single();

        if (existing) {
          // Already imported
          continue;
        }

        onProgress(`Processando: ${item.title.substring(0, 40)}...`);

        // Prepare content for Gemini
        const rawContent = item['content:encoded'] || item.content || item.description || '';
        const prompt = rewriteArticlePrompt(item.title, rawContent);

        try {
          // Gemini Call
          const result = await geminiModel.generateContent(prompt);
          const text = result.response.text();

          // Extract JSON block from output
          const jsonMatch = text.match(/\{[\s\S]*\}/);
          if (!jsonMatch) {
            console.warn('Could not extract JSON from Gemini response for:', item.title);
            continue;
          }

          const articleData = JSON.parse(jsonMatch[0]);

          // Images
          let imageUrl = extractImage(item);
          if (!imageUrl) {
            imageUrl = await getTMDBFallbackImage(articleData.title || item.title);
          }

          const altText = articleData.title || item.title;

          // Merge into DB
          const newArticle = {
             title: articleData.title,
             slug: articleData.slug.toLowerCase().replace(/[^a-z0-9-]/g, ''),
             content: articleData.content,
             meta_description: articleData.meta_description,
             status: 'draft',
             image_url: imageUrl,
             image_alt: altText,
             tags: articleData.tags,
             category: articleData.category,
             source_url: item.link
          };

          const { error: insertError } = await supabaseAdmin
            .from('articles')
            .insert(newArticle);

          if (insertError) {
             console.error('Error inserting article:', insertError);
          } else {
             onProgress(`Salvo com sucesso (Draft): ${articleData.title.substring(0, 30)}...`);
          }

        } catch (geminiError) {
          console.error('Error generating content with Gemini:', geminiError);
        }
      }
    } catch (err) {
      console.error(`Error processing feed ${source.name}:`, err);
      onProgress(`Erro no feed ${source.name}. Pulando...`);
    }
  }

  onProgress('Processamento finalizado!');
};

